nt-weight:800}.active{background:#eaf8f0;color:#168449}.partial{background:#fff6df;color:#a66800}.closed{background:#eef2f6;color:#5d6874}.overdue{background:#fdecec;color:#bd2d2d}.actions{display:flex;gap:6px}.ab{width:32px;height:32px;display:grid;place-items:center;border:1px solid var(--border);border-radius:8px;color:var(--text);text-decoration:none}.state{padding:42px;text-align:center;color:var(--muted)}.toastx{position:fixed;right:18px;top:78px;z-index:99999;background:#c0392b;color:#fff;padding:11px 14px;border-radius:10px;font-size:11px;box-shadow:0 14px 35px #0003}
@media(max-width:1199px){.stats,.minis{grid-template-columns:repeat(2,1fr)}.grid{grid-template-columns:repeat(2,1fr)}.s1,.s2,.s3,.s12{grid-column:span 1}}@media(max-width:991px){.responsive{min-width:0}.responsive thead,.responsive tfoot{display:none}.responsive tbody{display:grid;grid-template-columns:repeat(2,1fr);gap:10px;padding:10px}.responsive tr{display:grid;grid-template-columns:1fr 1fr;border:1px solid var(--border);border-radius:var(--radius);padding:12px}.responsive td{display:flex;justify-content:space-between;white-space:normal;border:0;border-bottom:1px dashed var(--border);padding:8px 0}.responsive td:before{content:attr(data-label);font-size:8px;font-weight:700;color:var(--muted);text-transform:uppercase}.actions{justify-content:flex-start}}@media(max-width:767px){.stats,.minis,.grid{grid-template-columns:1fr}.responsive tbody{grid-template-columns:1fr}.responsive tr{grid-template-columns:1fr}.responsive td{grid-column:1/-1}.ph{align-items:flex-start;flex-direction:column}}
