<div class="panel"><div class="ph"><div><div class="pt">Pawn Report Filters</div><div class="ps">Filter by date, customer, category, status, and keyword.</div></div><div class="d-flex gap-2"><button class="btn btn-lightx" id="printBtn"><i class="fa-solid fa-print me-1"></i>Print</button><button class="btn btn-lightx" id="excelBtn"><i class="fa-solid fa-file-excel me-1"></i>Excel</button></div></div><div class="pb"><form id="filterForm" class="grid"><div class="s2"><div class="fl">From Date</div><input type="date" name="from_date" class="form-control"></div><div class="s2"><div class="fl">To Date</div><input type="date" name="to_date" class="form-control"></div><div class="s3"><div class="fl">Customer</div><select name="customer_id" id="customer" class="form-select"><option value="0">All Customers</option></select></div><div class="s2"><div class="fl">Status</div><select name="status" class="form-select"><option value="">All Status</option><option>Draft</option><option>Active</option><option>Partially Paid</option><option>Closed</option><option>Auctioned</option><option>Cancelled</option></select></div><div class="s2"><div class="fl">Search</div><input type="search" name="search" class="form-control" placeholder="Pawn no, customer, mobile"></div><div class="s1 d-flex align-items-end"><button class="btn btn-theme w-100"><i class="fa-solid fa-filter me-1"></i>Apply</button></div><div class="s12"><button type="button" class="btn btn-lightx" id="resetBtn">Reset Filters</button></div></form></div></div>
<div class="minis"><div class="mini"><span>Gross Weight</span><strong id="gross">0.000 g</strong></div><div class="mini"><span>Net Weight</span><strong id="net">0.000 g</strong></div><div class="mini"><span>Principal Paid</span><strong id="paid">₹0.00</strong></div><div class="mini"><span>Estimated Interest</span><strong id="estimated">₹0.00</strong></div></div>
<div class="panel"><div class="ph"><div><div class="pt">Pawn Details</div><div class="ps" id="period">Loading...</div></div><button class="btn btn-lightx" id="refresh"><i class="fa-solid fa-rotate"></i></button></div><div id="loading" class="state"><i class="fa-solid fa-spinner fa-spin"></i><div>Loading pawn report...</div></div><div id="wrap" class="table-responsive d-none"><table class="table responsive"><thead><tr><th>#</th><th>Pawn No</th><th>Date</th><th>Customer</th><th>Mobile</th><th>Category</th><th>Gross Wt</th><th>Net Wt</th><th>Principal</th><th>Interest %</th><th>Interest Paid</th><th>Principal Paid</th><th>Balance</th><th>Due Date</th><th>Status</th><th>Action</th></tr></thead><tbody id="body"></tbody><tfoot id="foot"></tfoot></table></div><div id="empty" class="state d-none">No pawn records found.</div></div>
<?php include 'includes/footer.php'; ?></div></main><?php include 'includes/script.php'; ?><script src="assets/js/script.js"></script><script>
(()=>{'use strict';const form=document.getElementById('filterForm'),body=document.getElementById('body'),foot=document.getElementById('foot'),wrap=document.getElementById('wrap'),loading=document.getElementById('loading'),empty=document.getElementById('empty'),customer=document.getElementById('customer');const money=v=>Number(v||0).toLocaleString('en-IN',{minimumFractionDigits:2,maximumFractionDigits:2});const esc=v=>{const d=document.createElement('div');d.textContent=v??'';return d.innerHTML};function toast(m){const e=document.createElement('div');e.className='toastx';e.textContent=m;document.body.appendChild(e);setTimeout(()=>e.remove(),3500)}async function req(u){const r=await fetch(u,{credentials:'same-origin',headers:{Accept:'application/json','X-Requested-With':'XMLHttpRequest'}}),t=await r.text();let j;try{j=JSON.parse(t)}catch{throw new Error(t?'Server returned invalid output: '+t.slice(0,180):'Empty server response')}if(!r.ok||!j.success)throw new Error(j.message||'Request failed');return j}
function summary(s){document.getElementById('totalRecords').textContent=Number(s.total_records||0);document.getElementById('principal').textContent='₹'+money(s.principal_amount);document.getElementById('interest').textContent='₹'+money(s.interest_collected);document.getElementById('balance').textContent='₹'+money(s.balance_principal);document.getElementById('gross').textContent=Number(s.gross_weight||0).toFixed(3)+' g';document.getElementById('net').textContent=Number(s.net_weight||0).toFixed(3)+' g';document.getElementById('paid').textContent='₹'+money(s.principal_paid);document.getElementById('estimated').textContent='₹'+money(s.estimated_interest)}
function render(rows,s){loading.classList.add('d-none');if(!rows.length){wrap.classList.add('d-none');empty.classList.remove('d-none');return}empty.classList.add('d-none');wrap.classList.remove('d-none');body.innerHTML=rows.map((r,i)=>{const st=String(r.status||'Active'),cl=st==='Active'?'active':st==='Partially Paid'?'partial':st==='Closed'||st==='Auctioned'?'closed':'overdue';return `<tr><td data-label="#">${i+1}</td><td data-label="Pawn No"><strong>${esc(r.pawn_no)}</strong></td><td data-label="Date">${esc(r.pawn_date_display)}</td><td data-label="Customer">${esc(r.customer_name||'—')}</td><td data-label="Mobile">${esc(r.mobile||'—')}</td><td data-label="Category">${esc(r.category_name||'—')}</td><td data-label="Gross Wt">${Number(r.total_gross_weight||0).toFixed(3)}</td><td data-label="Net Wt">${Number(r.total_net_weight||0).toFixed(3)}</td><td data-label="Principal">₹${money(r.principal_amount)}</td><td data-label="Interest %">${Number(r.interest_percent||0).toFixed(3)}%</td><td data-label="Interest Paid">₹${money(r.total_interest_collected)}</td><td data-label="Principal Paid">₹${money(r.total_principal_paid)}</td><td data-label="Balance">₹${money(r.balance_principal)}</td><td data-label="Due Date">${esc(r.due_date_display)}</td><td data-label="Status"><span class="badge-status ${cl}">${esc(st)}</span></td><td data-label="Action"><div class="actions"><a class="ab" href="pawn-view.php?id=${Number(r.id)}" title="View"><i class="fa-solid fa-eye"></i></a><a class="ab" href="pawn-payments.php?pawn_id=${Number(r.id)}" title="Payment"><i class="fa-solid fa-indian-rupee-sign"></i></a></div></td></tr>`}).join('');foot.innerHTML=`<tr><td colspan="6" class="text-end"><strong>Totals</strong></td><td><strong>${Number(s.gross_weight||0).toFixed(3)}</strong></td><td><strong>${Number(s.net_weight||0).toFixed(3)}</strong></td><td><strong>₹${money(s.principal_amount)}</strong></td><td></td><td><strong>₹${money(s.interest_collected)}</strong></td><td><strong>₹${money(s.principal_paid)}</strong></td><td><strong>₹${money(s.balance_principal)}</strong></td><td colspan="3"></td></tr>`}
async function bootstrap(){const j=await req('api/pawn-reports.php?action=bootstrap');customer.innerHTML='<option value="0">All Customers</option>'+j.customers.map(c=>`<option value="${c.id}">${esc(c.customer_name)}${c.customer_code?' ('+esc(c.customer_code)+')':''}</option>`).join('');form.from_date.value=j.defaults.from_date;form.to_date.value=j.defaults.to_date}
async function load(){loading.classList.remove('d-none');wrap.classList.add('d-none');empty.classList.add('d-none');try{const p=new URLSearchParams(new FormData(form));p.set('action','list');const j=await req('api/pawn-reports.php?'+p);summary(j.summary);render(j.rows,j.summary);document.getElementById('period').textContent='Period: '+j.period.from_display+' to '+j.period.to_display}catch(e){loading.classList.add('d-none');empty.classList.remove('d-none');empty.textContent=e.message;toast(e.message)}}
form.addEventListener('submit',e=>{e.preventDefault();load()});document.getElementById('resetBtn').onclick=async()=>{form.reset();await bootstrap();load()};document.getElementById('refresh').onclick=load;document.getElementById('printBtn').onclick=()=>window.print();document.getElementById('excelBtn').onclick=()=>{const p=new URLSearchParams(new FormData(form));p.set('action','export');location.href='api/pawn-reports.php?'+p};bootstrap().then(load).catch(e=>toast(e.message));})();
</script></body></html>
